(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[44091],{89642:function(e,t,n){(window.__NEXT_P=window.__NEXT_P||[]).push(["/en/blog/announcements/retiring-the-node-js-community-committee",function(){return n(5555)}])},5555:function(e,t,n){"use strict";n.r(t),n.d(t,{__N_SSG:function(){return c}});var i=n(26042),o=n(69396),s=n(85893),r=n(48863),a=n(11151);function h(e){var t=Object.assign({h1:"h1",p:"p",strong:"strong",h2:"h2",a:"a",em:"em",ul:"ul",li:"li"},(0,a.ah)(),e.components);return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.h1,{children:"Retiring the Node.js Community Committee"}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"tl;dr:"})," we're going to be retiring the Node.js Community Committee, moving our existing Initiatives to exist under the Node.js Technical Steering Committee (TSC)."]}),"\n",(0,s.jsx)(t.p,{children:"From the Community Committee's side, we've seen a convergence of our initiatives' goals with the goals of the work that is generally under the TSC. Further, we've seen a decline in the number of people who can consistently dedicate the necessary amount of time/energy. As such, separation between the TSC and Community Committee has become more of a barrier to accomplishing our collective goals rather than the helpful and necessary construct it once was."}),"\n",(0,s.jsx)(t.h2,{id:"the-past",children:"The Past"}),"\n",(0,s.jsx)(t.p,{children:"I want to start with a bit of history as a form of preservation of the context I've collected as the Community Committee's chair for the majority of its existence."}),"\n",(0,s.jsxs)(t.p,{children:["On January 11th, 2017, ",(0,s.jsx)(t.a,{href:"https://twitter.com/hackygolucky",children:"Tracy Hinds"})," made the first commit to the ",(0,s.jsx)(t.a,{href:"https://github.com/nodejs/community-committee/commit/1902cdc71c8e62e65a5bab4cca9a21d5b5e744c0",children:"nodejs/community-committee"})," repository. This commit was the result of in-person discussion with a number of key Node.js community members at the 2016 North America Collaborator Summit in Austin, Texas, though there'd been a rising discourse to push for something like it for some time in various forums including the (now-archived) ",(0,s.jsx)(t.a,{href:"https://github.com/nodejs/inclusivity",children:"Inclusivity WG"}),"."]}),"\n",(0,s.jsxs)(t.p,{children:["The stated goal of the Community Committee has been to be a ",(0,s.jsx)(t.em,{children:"top-level"})," commitment of and investment in the Node.js project to support community efforts."]}),"\n",(0,s.jsx)(t.p,{children:"At the time, this was particularly important. Node.js as a project was still figuring out its identity as a project independent from a Corporation while existing in a neutral Foundation. The Node.js community was foundational not only in the project's success - be it in the v0.x era in the early 2010s, during the io.js fork, or post-reunification - and those starting the Committee wanted to be sure that we were effectively representing and enabling that from the project directly."}),"\n",(0,s.jsx)(t.h2,{id:"the-present",children:"The Present"}),"\n",(0,s.jsx)(t.p,{children:"Since the creation of the Node.js Community Committee, members have largely spent project and committee time on outward-facing efforts with the goal of continuing to enable and grow the Node.js community. There've been multiple facets to this approach, some of which have been relatively successful and others that have been entirely unsuccessful."}),"\n",(0,s.jsx)(t.p,{children:"The broad trend that I've personally witnessed is that the Community Committee's interest and activity have slowed dramatically since its inception. My perception is that this is due to a couple of different factors:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Sponsorship and Investment:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:['A majority of work in Node.js is done by people who can dedicate non-trivial amounts of their paid time to progress the project, sponsored by their employer. Initially, there was already a small number of people who were able to focus their employer-sponsored time on "community" work - work that doesn\'t ship features they need - in Node.js, and that number has only gone down over time.',"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:["I ",(0,s.jsx)(t.em,{children:"do not"})," think that this will be a universal experience in open source. Several other massive-scale projects are relatively successful in approaching this. They also have fundamentally different models and investment than Node.js does, which is likely a contributing factor to their sustainability. The ",(0,s.jsx)(t.a,{href:"https://github.com/electron/governance/tree/main/wg-outreach",children:"Electron Outreach WG"})," and the ",(0,s.jsx)(t.a,{href:"https://github.com/kubernetes/community/tree/master/sig-contributor-experience",children:"Kubernetes Contributor Experience SIG"}),' are both good examples of "success" here, in my opinion.']}),"\n"]}),"\n"]}),"\n",(0,s.jsx)(t.li,{children:"In general, JavaScript occupies a relatively unique space. It is ubiquitous, yet very few companies are willing to substantially invest time, energy, and resources into it despite their reliance on it. Lack of investment into community sustainability is one facet of this."}),"\n"]}),"\n"]}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Necessity:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"The Node.js Community Committee was created at a time in which the Node.js project was larger, with louder voices sharing relatively differing opinions on how we should approach the future. The reality is that we're smaller now than we were then, and there's generally less conflict around how we should approach community, safety, and governance. As such, the necessity for a distinct \"community\" focus is not only less but - in my opinion - actively detrimental to progress. It splits the project's collaborators into different, disconnected groups rather than unifying the project towards the same goal."}),"\n",(0,s.jsx)(t.li,{children:"The Node.js Community Committee was also created at a time when Node.js was relatively alone. Under the Node.js Foundation, we had to do a lot of community organization within the project directly. Under the OpenJS Foundation, we have shifted several initiatives that the Community Committee was charged with under the Node.js foundation up to the OpenJS Foundation Cross-project Council. As such, certain tasks that we initially envisioned being core to the Community Committee are now living in a different home."}),"\n"]}),"\n"]}),"\n"]}),"\n",(0,s.jsx)(t.h2,{id:"the-future",children:"The Future"}),"\n",(0,s.jsx)(t.p,{children:"I don't believe that retiring the Node.js Community Committee means we'll see a lack of investment in the community from the Node.js project."}),"\n",(0,s.jsxs)(t.p,{children:["Rather, I think it's an enabling function for Node.js to continue to ",(0,s.jsx)(t.strong,{children:"sustainably"})," invest in the community. This means fewer barriers, more connectedness, and allowing for resilience in the ebb and flow of those who can invest to do so."]}),"\n",(0,s.jsx)(t.p,{children:"I look forward to what we'll collectively work on next."}),"\n",(0,s.jsx)(t.h2,{id:"a-big-heartfelt-thanks",children:"A Big, Heartfelt Thanks"}),"\n",(0,s.jsxs)(t.p,{children:["Over the years, we've seen ",(0,s.jsx)(t.a,{href:"https://github.com/nodejs/community-committee/graphs/contributors",children:"dozens of people"})," contribute to the Node.js Community Committee and ",(0,s.jsx)(t.a,{href:"https://github.com/nodejs/community-committee#current-initiatives",children:"its initiatives"}),", and I'd like to be explicit:"]}),"\n",(0,s.jsxs)(t.p,{children:["Y'all have been lovely over the past five years. You all care deeply about the Node.js ecosystem, community, and ",(0,s.jsx)(t.em,{children:"people"}),". It's been truly a privilege to have the opportunity to work on something like this with each and every one of you."]}),"\n",(0,s.jsx)(t.p,{children:"As we retire the CommComm, I hope that you see this as yet another evolution of the Node.js project's commitment to the community... just as the CommComm itself was."})]})}n(25675);var c=!0;t.default=(0,r.j)({MDXContent:function(){var e=arguments.length>0&&void 0!==arguments[0]?arguments[0]:{},t=Object.assign({},(0,a.ah)(),e.components).wrapper;return t?(0,s.jsx)(t,(0,o.Z)((0,i.Z)({},e),{children:(0,s.jsx)(h,(0,i.Z)({},e))})):h(e)},pageOpts:{filePath:"pages/en/blog/announcements/retiring-the-node-js-community-committee.md",route:"/en/blog/announcements/retiring-the-node-js-community-committee",frontMatter:{date:"2021-10-07T20:00:00.000Z",category:"announcements",title:"Retiring the Node.js Community Committee",slug:"retiring-the-node-js-community-committee",layout:"blog-post.hbs",author:"Tierney Cyren"},title:"Retiring the Node.js Community Committee"},pageNextRoute:"/en/blog/announcements/retiring-the-node-js-community-committee"})}},function(e){e.O(0,[48863,49774,92888,40179],function(){return e(e.s=89642)}),_N_E=e.O()}]);